{
  "name": "Iceland Highlands Overlander",
  "description": "An interactive trip planning and visualization tool for an off-road 4x4 F-road expedition through Iceland's remote highlands.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

export interface Coordinate {
  lat: number;
  lng: number;
}

export interface POI {
  name: string;
  type: 'waterfall' | 'volcano' | 'hotspring' | 'town' | 'canyon' | 'other' | 'camp';
  coord: Coordinate;
  description?: string;
}

export interface ItineraryDay {
  date: string;
  dayNum: number;
  title: string;
  where: string;
  activities: string[];
  sleep: string;
  routeCoords: Coordinate[]; // Primary route
  pois: POI[];
  isHighland: boolean;
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

import { GoogleGenAI } from "@google/genai";
import { ICELAND_ITINERARY } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `
You are an expert Iceland Expedition Guide specializing in off-road 4x4 overlanding and F-Road navigation.
The user is planning a trip in August/September 2026. 
You have access to their planned itinerary:
${JSON.stringify(ICELAND_ITINERARY, null, 2)}

Key expertise areas:
1. F-Road conditions: Explain the difficulty of F26, F88, F208, and F249.
2. River crossings: Advise on how to gauge depth and the risk of rain.
3. Overlanding gear: Recommendations for modified 4x4s, fuel cans, and emergency beacons.
4. Weather: August variability, wind warnings, and sandstorms.
5. Scenic hidden gems near their planned route.

Always be encouraging but prioritize safety. If they ask about river crossings, emphasize that high-water events can happen even in August.
Keep responses concise and adventurous. Use Markdown for formatting.
`;

export async function getGeminiAdvice(messages: { role: 'user' | 'model', text: string }[]) {
  try {
    const chat = ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: messages.map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      })),
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
      }
    });

    const response = await chat;
    return response.text || "I'm sorry, I couldn't process that. Try again!";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "The adventure guide is currently out of range (API Error). Check your connection and try again.";
  }
}

import React, { useEffect, useRef } from 'react';
import { ItineraryDay, POI } from '../types';

interface MapProps {
  days: ItineraryDay[];
  selectedDay: number | null;
  onSelectDay: (dayNum: number) => void;
}

const Map: React.FC<MapProps> = ({ days, selectedDay, onSelectDay }) => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstanceRef = useRef<any>(null);
  const layersRef = useRef<{ [key: string]: any }>({});

  useEffect(() => {
    if (!mapContainerRef.current || mapInstanceRef.current) return;

    // Initialize map
    const map = (window as any).L.map(mapContainerRef.current).setView([64.9, -18.5], 6.5);
    mapInstanceRef.current = map;

    // Add high quality topographical tiles
    (window as any).L.tileLayer('https://{s}.tile.opentopomap.org/{z}/{x}/{y}.png', {
      maxZoom: 17,
      attribution: 'Map data: &copy; OpenStreetMap, SRTM | Map style: &copy; OpenTopoMap (CC-BY-SA)'
    }).addTo(map);

    // Initial draw
    drawItinerary(map);

    return () => {
      if (mapInstanceRef.current) {
        mapInstanceRef.current.remove();
        mapInstanceRef.current = null;
      }
    };
  }, []);

  const drawItinerary = (map: any) => {
    // Clear previous layers
    Object.values(layersRef.current).forEach(layer => map.removeLayer(layer));
    layersRef.current = {};

    days.forEach((day) => {
      const isSelected = selectedDay === day.dayNum;

      // Draw path
      const path = (window as any).L.polyline(
        day.routeCoords.map(c => [c.lat, c.lng]),
        {
          color: day.isHighland ? '#f59e0b' : '#3b82f6',
          weight: isSelected ? 6 : 3,
          opacity: isSelected ? 1 : 0.6,
          dashArray: day.isHighland ? '10, 10' : undefined
        }
      ).addTo(map);

      path.on('click', () => onSelectDay(day.dayNum));
      layersRef.current[`path_${day.dayNum}`] = path;

      // Draw POIs if selected or basic markers
      day.pois.forEach(poi => {
        const marker = (window as any).L.circleMarker([poi.coord.lat, poi.coord.lng], {
          radius: isSelected ? 8 : 5,
          fillColor: getPoiColor(poi.type),
          color: '#fff',
          weight: 2,
          opacity: 1,
          fillOpacity: 0.8
        }).addTo(map);

        marker.bindPopup(`<b>${poi.name}</b><br/>${poi.type}`);
        layersRef.current[`poi_${day.dayNum}_${poi.name}`] = marker;
      });
    });
  };

  useEffect(() => {
    if (mapInstanceRef.current) {
      drawItinerary(mapInstanceRef.current);

      if (selectedDay) {
        const day = days.find(d => d.dayNum === selectedDay);
        if (day && day.routeCoords.length > 0) {
          mapInstanceRef.current.panTo([day.routeCoords[0].lat, day.routeCoords[0].lng]);
        }
      }
    }
  }, [selectedDay]);

  const getPoiColor = (type: POI['type']) => {
    switch (type) {
      case 'waterfall': return '#0ea5e9';
      case 'volcano': return '#ef4444';
      case 'hotspring': return '#10b981';
      case 'town': return '#6366f1';
      case 'canyon': return '#a855f7';
      default: return '#71717a';
    }
  };

  return <div ref={mapContainerRef} className="h-full w-full rounded-xl overflow-hidden shadow-2xl border-4 border-white" />;
};

export default Map;

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, X, Minimize2, Maximize2 } from 'lucide-react';
import { getGeminiAdvice } from '../services/geminiService';
import { ChatMessage } from '../types';

const ChatWindow: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: "Ready to conquer the F-roads? I'm your expedition guide. Ask me about river crossings, gear, or hidden highland spots!" }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isOpen, setIsOpen] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = { role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    const responseText = await getGeminiAdvice([...messages, userMsg]);
    setMessages(prev => [...prev, { role: 'model', text: responseText }]);
    setIsLoading(false);
  };

  if (!isOpen) {
    return (
      <button 
        onClick={() => setIsOpen(true)}
        className="fixed bottom-6 right-6 bg-slate-900 text-white p-4 rounded-full shadow-2xl hover:bg-slate-800 transition-all flex items-center gap-2 z-50 group"
      >
        <Bot size={24} />
        <span className="max-w-0 overflow-hidden group-hover:max-w-xs transition-all duration-300 whitespace-nowrap">Ask Guide</span>
      </button>
    );
  }

  return (
    <div className="fixed bottom-6 right-6 w-96 max-h-[600px] h-[70vh] bg-white rounded-2xl shadow-2xl flex flex-col z-50 border border-slate-200 overflow-hidden animate-in slide-in-from-bottom-5">
      <div className="bg-slate-900 p-4 text-white flex justify-between items-center shrink-0">
        <div className="flex items-center gap-2">
          <Bot size={20} className="text-blue-400" />
          <h3 className="font-bold">Expedition AI</h3>
        </div>
        <button onClick={() => setIsOpen(false)} className="hover:text-slate-300">
          <Minimize2 size={18} />
        </button>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-3 rounded-2xl ${
              m.role === 'user' 
                ? 'bg-blue-600 text-white rounded-tr-none' 
                : 'bg-white text-slate-800 shadow-sm border border-slate-200 rounded-tl-none'
            }`}>
              <div className="prose prose-sm prose-slate max-w-none">
                 {m.text.split('\n').map((line, idx) => (
                   <p key={idx} className="mb-2 last:mb-0 leading-relaxed text-sm">
                     {line}
                   </p>
                 ))}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-white p-3 rounded-2xl shadow-sm border border-slate-200 rounded-tl-none flex gap-1">
              <span className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce" />
              <span className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce [animation-delay:0.2s]" />
              <span className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce [animation-delay:0.4s]" />
            </div>
          </div>
        )}
      </div>

      <div className="p-4 border-t border-slate-100 bg-white shrink-0">
        <div className="flex gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Ask about F-Roads..."
            className="flex-1 bg-slate-100 border-none rounded-xl px-4 py-2 focus:ring-2 focus:ring-blue-500 outline-none text-sm"
          />
          <button 
            onClick={handleSend}
            disabled={isLoading}
            className="bg-blue-600 text-white p-2 rounded-xl hover:bg-blue-700 disabled:opacity-50 transition-colors"
          >
            <Send size={20} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default ChatWindow;

