import React, { useEffect, useRef } from 'react';
import { ItineraryDay, POI } from '../types';

interface MapProps {
  days: ItineraryDay[];
  selectedDay: number | null;
  onSelectDay: (dayNum: number) => void;
}

const Map: React.FC<MapProps> = ({ days, selectedDay, onSelectDay }) => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstanceRef = useRef<any>(null);
  const layersRef = useRef<{ [key: string]: any }>({});

  useEffect(() => {
    if (!mapContainerRef.current || mapInstanceRef.current) return;

    // Initialize map
    const map = (window as any).L.map(mapContainerRef.current, {
      zoomControl: false
    }).setView([64.9, -18.5], 6.5);
    mapInstanceRef.current = map;

    // Add high quality satellite tiles
    (window as any).L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}', {
      maxZoom: 19,
      attribution: 'Tiles &copy; Esri &mdash; Source: Esri, i-cubed, USDA, USGS, AEX, GeoEye, Getmapping, Aerogrid, IGN, IGP, UPR-EBP, and the GIS User Community'
    }).addTo(map);

    // Zoom control at bottom right
    (window as any).L.control.zoom({
      position: 'bottomright'
    }).addTo(map);

    // Initial draw
    drawItinerary(map);

    return () => {
      if (mapInstanceRef.current) {
        mapInstanceRef.current.remove();
        mapInstanceRef.current = null;
      }
    };
  }, []);

  const drawItinerary = (map: any) => {
    // Clear previous layers
    Object.values(layersRef.current).forEach(layer => map.removeLayer(layer));
    layersRef.current = {};

    days.forEach((day) => {
      const isSelected = selectedDay === day.dayNum;

      // Draw path with neon colors for satellite contrast
      const path = (window as any).L.polyline(
        day.routeCoords.map(c => [c.lat, c.lng]),
        {
          color: day.isHighland ? '#facc15' : '#0ea5e9',
          weight: isSelected ? 8 : 4,
          opacity: isSelected ? 1 : 0.4,
          dashArray: day.isHighland ? '10, 15' : undefined
        }
      ).addTo(map);

      path.on('click', () => onSelectDay(day.dayNum));
      layersRef.current[`path_${day.dayNum}`] = path;

      // Draw POIs
      day.pois.forEach(poi => {
        const marker = (window as any).L.circleMarker([poi.coord.lat, poi.coord.lng], {
          radius: isSelected ? 8 : 5,
          fillColor: getPoiColor(poi.type),
          color: '#fff',
          weight: 2,
          opacity: 1,
          fillOpacity: 0.9
        }).addTo(map);

        marker.bindPopup(`<div class="p-1"><b class="text-slate-900">${poi.name}</b><br/><span class="text-slate-500 text-xs">${poi.type}</span></div>`);
        layersRef.current[`poi_${day.dayNum}_${poi.name}`] = marker;
      });
    });
  };

  useEffect(() => {
    if (mapInstanceRef.current) {
      drawItinerary(mapInstanceRef.current);

      if (selectedDay) {
        const day = days.find(d => d.dayNum === selectedDay);
        if (day && day.routeCoords.length > 0) {
          mapInstanceRef.current.flyTo([day.routeCoords[0].lat, day.routeCoords[0].lng], isMobile() ? 9 : 10, {
            duration: 1.5
          });
        }
      }
    }
  }, [selectedDay]);

  const isMobile = () => window.innerWidth < 1024;

  const getPoiColor = (type: POI['type']) => {
    switch (type) {
      case 'waterfall': return '#38bdf8';
      case 'volcano': return '#f87171';
      case 'hotspring': return '#4ade80';
      case 'town': return '#818cf8';
      case 'canyon': return '#c084fc';
      default: return '#94a3b8';
    }
  };

  return <div ref={mapContainerRef} className="h-full w-full rounded-2xl overflow-hidden shadow-2xl border-2 border-slate-800" />;
};

export default Map;

