import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, Minimize2 } from 'lucide-react';
import { getGeminiAdvice } from '../services/geminiService';
import { ChatMessage } from '../types';

const ChatWindow: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: "Expedition status: Online. I'm your AI guide for the Icelandic Highlands. Ask me about river crossings, F-road difficulty, or wild camping regulations." }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isOpen, setIsOpen] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = { role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    const responseText = await getGeminiAdvice([...messages, userMsg]);
    setMessages(prev => [...prev, { role: 'model', text: responseText }]);
    setIsLoading(false);
  };

  if (!isOpen) {
    return (
      <button 
        onClick={() => setIsOpen(true)}
        className="fixed bottom-6 right-6 bg-blue-600 text-white p-5 rounded-full shadow-[0_10px_40px_-10px_rgba(37,99,235,0.6)] hover:bg-blue-500 transition-all flex items-center gap-3 z-50 group border border-blue-400/30"
      >
        <Bot size={24} className="group-hover:rotate-12 transition-transform" />
        <span className="max-w-0 overflow-hidden group-hover:max-w-xs transition-all duration-300 whitespace-nowrap font-bold text-sm">Expedition Guide</span>
      </button>
    );
  }

  return (
    <div className="fixed bottom-6 right-6 w-96 max-h-[600px] h-[70vh] bg-slate-900 rounded-[2rem] shadow-[0_20px_60px_-15px_rgba(0,0,0,0.8)] flex flex-col z-50 border border-slate-700 overflow-hidden animate-in slide-in-from-bottom-8 duration-500">
      <div className="bg-slate-800 p-5 text-white flex justify-between items-center shrink-0 border-b border-slate-700">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-blue-600 rounded-lg">
            <Bot size={20} />
          </div>
          <div>
            <h3 className="font-bold text-sm">Expedition Intelligence</h3>
            <div className="flex items-center gap-1.5">
              <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse" />
              <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Satellite Active</span>
            </div>
          </div>
        </div>
        <button onClick={() => setIsOpen(false)} className="hover:text-slate-300 p-2 hover:bg-slate-700 rounded-full transition-colors">
          <Minimize2 size={18} />
        </button>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-5 space-y-6 bg-slate-950/50">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-4 rounded-2xl ${
              m.role === 'user' 
                ? 'bg-blue-600 text-white rounded-tr-none shadow-lg' 
                : 'bg-slate-800 text-slate-200 border border-slate-700 rounded-tl-none shadow-inner'
            }`}>
              <div className="prose prose-invert prose-sm max-w-none">
                 {m.text.split('\n').map((line, idx) => (
                   <p key={idx} className="mb-2 last:mb-0 leading-relaxed text-sm">
                     {line}
                   </p>
                 ))}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-slate-800 p-4 rounded-2xl border border-slate-700 rounded-tl-none flex gap-1.5">
              <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce" />
              <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce [animation-delay:0.2s]" />
