import React, { useEffect, useRef, useCallback } from 'react';
import { ItineraryDay, POI } from '../types';

interface MapProps {
  days: ItineraryDay[];
  selectedDay: number | null;
  onSelectDay: (dayNum: number) => void;
}

const Map: React.FC<MapProps> = ({ days, selectedDay, onSelectDay }) => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstanceRef = useRef<any>(null);
  const layersRef = useRef<{ [key: string]: any }>({});

  const isMobile = () => typeof window !== 'undefined' && window.innerWidth < 1024;

  const getPoiColor = (type: POI['type']) => {
    switch (type) {
      case 'waterfall': return '#38bdf8';
      case 'volcano': return '#f87171';
      case 'hotspring': return '#4ade80';
      case 'town': return '#818cf8';
      case 'canyon': return '#fb923c';
      default: return '#94a3b8';
    }
  };

  const drawItinerary = useCallback((map: any) => {
    if (!map) return;

    // Clear previous layers safely
    Object.values(layersRef.current).forEach(layer => {
      if (layer && map.hasLayer(layer)) {
        map.removeLayer(layer);
      }
    });
    layersRef.current = {};

    days.forEach((day) => {
      if (!day.routeCoords || day.routeCoords.length === 0) return;

      const isSelected = selectedDay === day.dayNum;

      // Filter and validate points to prevent NaN errors
      const validPoints = day.routeCoords
        .filter(c => c && typeof c.lat === 'number' && typeof c.lng === 'number' && !isNaN(c.lat) && !isNaN(c.lng))
        .map(c => [c.lat, c.lng]);

      if (validPoints.length >= 2) {
        const path = (window as any).L.polyline(validPoints, {
          color: day.isHighland ? '#facc15' : '#0ea5e9',
          weight: isSelected ? 8 : 4,
          opacity: isSelected ? 1 : 0.4,
          dashArray: day.isHighland ? '10, 15' : undefined,
          interactive: true
        }).addTo(map);

        path.on('click', (e: any) => {
          (window as any).L.DomEvent.stopPropagation(e);
          onSelectDay(day.dayNum);
        });
        layersRef.current[`path_${day.dayNum}`] = path;
      }

      // Draw POIs with validation
      day.pois.forEach(poi => {
        if (!poi.coord || typeof poi.coord.lat !== 'number' || typeof poi.coord.lng !== 'number' || isNaN(poi.coord.lat) || isNaN(poi.coord.lng)) return;

        const marker = (window as any).L.circleMarker([poi.coord.lat, poi.coord.lng], {
          radius: isSelected ? 10 : 6,
          fillColor: getPoiColor(poi.type),
          color: isSelected ? '#fff' : '#000',
          weight: 2,
          opacity: 1,
          fillOpacity: 0.95
        }).addTo(map);

        const popupContent = `
          <div class="w-64 overflow-hidden rounded-lg font-sans text-slate-900">
            ${poi.imageUrl ? `<img src="${poi.imageUrl}" class="w-full h-32 object-cover mb-2 rounded-t-lg shadow-sm" alt="${poi.name}" />` : ''}
            <div class="p-2">
              <div class="flex justify-between items-start mb-1">
                <b class="text-slate-900 text-lg leading-tight">${poi.name}</b>
                <span class="bg-blue-600 text-white text-[10px] px-2 py-0.5 rounded-full font-bold shrink-0 ml-2">DAY ${day.dayNum}</span>
              </div>
              <p class="text-slate-500 text-[10px] uppercase tracking-widest font-bold mb-2">${poi.type}</p>
              <p class="text-slate-700 text-xs leading-relaxed">Expedition waypoint for ${day.date}.</p>
            </div>
          </div>
        `;

        marker.bindPopup(popupContent, {
          className: 'custom-leaflet-popup',
          offset: [0, -5]
        });

        marker.on('click', (e: any) => {
          (window as any).L.DomEvent.stopPropagation(e);
          onSelectDay(day.dayNum);
        });
        layersRef.current[`poi_${day.dayNum}_${poi.name}`] = marker;
      });
    });
  }, [days, selectedDay, onSelectDay]);

  useEffect(() => {
    if (!mapContainerRef.current || mapInstanceRef.current) return;

    // Initialize map
    const map = (window as any).L.map(mapContainerRef.current, {
      zoomControl: false,
      attributionControl: true
    }).setView([64.9, -18.5], 6.5);

    mapInstanceRef.current = map;

    // Satellite imagery
    (window as any).L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}', {
      maxZoom: 19,
      attribution: 'Tiles &copy; Esri'
    }).addTo(map);

    (window as any).L.control.zoom({
      position: 'bottomright'
    }).addTo(map);

    drawItinerary(map);

    // Initial focus if selectedDay exists
    if (selectedDay) {
      const day = days.find(d => d.dayNum === selectedDay);
      if (day && day.routeCoords?.[0]) {
        const start = day.routeCoords[0];
        if (!isNaN(start.lat) && !isNaN(start.lng)) {
          map.setView([start.lat, start.lng], isMobile() ? 9 : 10);
        }
      }
    }

    return () => {
      if (mapInstanceRef.current) {
        mapInstanceRef.current.remove();
        mapInstanceRef.current = null;
      }
    };
  }, []);

  // Update map on day change
  useEffect(() => {
    const map = mapInstanceRef.current;
    if (map) {
      drawItinerary(map);

      if (selectedDay) {
        const day = days.find(d => d.dayNum === selectedDay);
        if (day && day.routeCoords?.[0]) {
          const start = day.routeCoords[0];
          if (!isNaN(start.lat) && !isNaN(start.lng)) {
            map.invalidateSize();
            map.flyTo([start.lat, start.lng], isMobile() ? 9 : 10, {
              duration: 1.2,
              easeLinearity: 0.25
            });
          }
        }
      }
    }
  }, [selectedDay, drawItinerary, days]);

  return <div ref={mapContainerRef} className="h-full w-full rounded-2xl overflow-hidden shadow-2xl border-2 border-slate-800 bg-slate-950" />;
};

export default Map;

