import React, { useEffect, useRef, useCallback } from 'react';
import { ItineraryDay, POI } from '../types';
import { getPronunciationAudio, decodeBase64, decodeAudioData } from '../services/geminiService';

interface MapProps {
  days: ItineraryDay[];
  selectedDay: number | null;
  onSelectDay: (dayNum: number) => void;
}

const Map: React.FC<MapProps> = ({ days, selectedDay, onSelectDay }) => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstanceRef = useRef<any>(null);
  const layersRef = useRef<{ [key: string]: any }>({});
  const lastSelectedDayRef = useRef<number | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);

  // Use a ref to track if the last change was triggered by a map interaction
  const isMapInteraction = useRef(false);

  const isMobile = () => typeof window !== 'undefined' && window.innerWidth < 1024;

  const handlePronounce = async (text: string, button: HTMLElement) => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }

    const ctx = audioContextRef.current;
    if (ctx.state === 'suspended') {
      await ctx.resume();
    }

    button.classList.add('animate-pulse', 'text-blue-500');
    button.setAttribute('disabled', 'true');

    try {
      const base64Audio = await getPronunciationAudio(text);
      if (base64Audio) {
        const audioData = decodeBase64(base64Audio);
        const buffer = await decodeAudioData(audioData, ctx, 24000, 1);
        const source = ctx.createBufferSource();
        source.buffer = buffer;
        source.connect(ctx.destination);
        source.start();

        source.onended = () => {
          button.classList.remove('animate-pulse', 'text-blue-500');
          button.removeAttribute('disabled');
        };
      } else {
        throw new Error("No audio data");
      }
    } catch (err) {
      console.error("Pronunciation failed", err);
      button.classList.remove('animate-pulse', 'text-blue-500');
      button.classList.add('text-red-500');
      setTimeout(() => {
        button.classList.remove('text-red-500');
        button.removeAttribute('disabled');
      }, 2000);
    }
  };

  const getPoiColor = (type: POI['type']) => {
    switch (type) {
      case 'waterfall': return '#38bdf8';
      case 'volcano': return '#f87171';
      case 'hotspring': return '#4ade80';
      case 'town': return '#818cf8';
      case 'canyon': return '#fb923c';
      default: return '#94a3b8';
    }
  };

  const drawItinerary = useCallback((map: any) => {
    if (!map) return;

    // Clear previous layers safely
    Object.values(layersRef.current).forEach(layer => {
      if (layer && map.hasLayer(layer)) {
        map.removeLayer(layer);
      }
    });
    layersRef.current = {};

    days.forEach((day) => {
      if (!day.routeCoords || day.routeCoords.length === 0) return;

      const isSelected = selectedDay === day.dayNum;

      // Filter and validate points
      const validPoints = day.routeCoords
        .filter(c => c && typeof c.lat === 'number' && typeof c.lng === 'number' && !isNaN(c.lat) && !isNaN(c.lng))
        .map(c => [c.lat, c.lng]);

      if (validPoints.length >= 2) {
        const path = (window as any).L.polyline(validPoints, {
          color: day.isHighland ? '#facc15' : '#0ea5e9',
          weight: isSelected ? 8 : 4,
          opacity: isSelected ? 1 : 0.4,
          dashArray: day.isHighland ? '10, 15' : undefined,
          interactive: true
        }).addTo(map);

        path.on('click', (e: any) => {
          (window as any).L.DomEvent.stopPropagation(e);
          if (selectedDay !== day.dayNum) {
            isMapInteraction.current = true; // Mark as map interaction
            onSelectDay(day.dayNum);
          }
        });
        layersRef.current[`path_${day.dayNum}`] = path;

        // Add Directional Arrows
        if (isSelected || day.dayNum === selectedDay) {
          for (let i = 0; i < validPoints.length - 1; i++) {
             const start = validPoints[i];
             const end = validPoints[i+1];
             const mid = [(start[0] + end[0]) / 2, (start[1] + end[1]) / 2];

             const dy = end[0] - start[0];
             const dx = end[1] - start[1];
             const bearing = Math.atan2(dx, dy) * 180 / Math.PI;
             const rotation = bearing;

             const arrow = (window as any).L.marker(mid, {
                icon: (window as any).L.divIcon({
                   className: 'direction-arrow',
                   html: `<div style="transform: rotate(${rotation}deg); color: ${day.isHighland ? '#facc15' : '#0ea5e9'}; font-size: 20px; font-weight: bold; text-shadow: 0 0 5px rgba(0,0,0,0.8)">➤</div>`,
                   iconSize: [20, 20],
                   iconAnchor: [10, 10]
                }),
                interactive: false
             }).addTo(map);
             layersRef.current[`arrow_${day.dayNum}_${i}`] = arrow;
          }
        }
      }

      // Draw POIs
      day.pois.forEach(poi => {
        if (!poi.coord || typeof poi.coord.lat !== 'number' || typeof poi.coord.lng !== 'number' || isNaN(poi.coord.lat) || isNaN(poi.coord.lng)) return;

        const marker = (window as any).L.circleMarker([poi.coord.lat, poi.coord.lng], {
          radius: isSelected ? 12 : 8,
          fillColor: getPoiColor(poi.type),
          color: isSelected ? '#fff' : '#000',
          weight: isSelected ? 3 : 2,
          opacity: 1,
          fillOpacity: 0.95
        }).addTo(map);

        const difficultyColor = poi.difficulty === 'Extreme' ? 'text-red-500' : poi.difficulty === 'Technical' ? 'text-orange-500' : 'text-green-500';

        const popupContent = `
          <div class="w-64 sm:w-72 overflow-hidden rounded-xl font-sans text-slate-900 bg-white" data-poi-name="${poi.name}">
            ${poi.imageUrl ? `<img src="${poi.imageUrl}" class="w-full h-28 sm:h-40 object-cover rounded-t-xl" alt="${poi.name}" onerror="this.src='https://images.unsplash.com/photo-1476610182048-b716b8518aae?auto=format&fit=crop&w=400&q=80'" />` : ''}
            <div class="p-2.5 sm:p-4">
              <div class="flex justify-between items-start mb-0.5 sm:mb-1">
                <div class="flex items-center gap-2">
                  <b class="text-slate-900 text-lg sm:text-xl font-black leading-tight">${poi.name}</b>
                  <button class="pronounce-btn p-1 text-slate-400 hover:text-blue-600 transition-colors" title="Listen to pronunciation">
                    <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M11 5L6 9H2v6h4l5 4V5z"></path><path d="M15.54 8.46a5 5 0 0 1 0 7.07"></path><path d="M19.07 4.93a10 10 0 0 1 0 14.14"></path></svg>
                  </button>
                </div>
                <span class="bg-slate-950 text-white text-[9px] sm:text-[10px] px-2 py-0.5 sm:py-1 rounded-full font-black shrink-0 ml-2">DAY ${day.dayNum}</span>
              </div>
              <div class="flex items-center gap-1.5 sm:gap-2 mb-2 sm:mb-3">
                <span class="text-slate-500 text-[9px] sm:text-[10px] uppercase tracking-widest font-black">${poi.type}</span>
                <span class="text-slate-300">•</span>
                <span class="text-[9px] sm:text-[10px] font-bold ${difficultyColor}">${poi.difficulty || 'Easy'} Terrain</span>
              </div>

              <div class="grid grid-cols-2 gap-1.5 sm:gap-2 mb-2 sm:mb-3 bg-slate-50 p-1.5 sm:p-2 rounded-lg border border-slate-100">
                <div>
                   <p class="text-[8px] sm:text-[9px] text-slate-400 font-bold uppercase">Elevation</p>
                   <p class="text-[10px] sm:text-xs font-bold text-slate-700">${poi.elevation || 'Sea Level'}</p>
                </div>
                <div>
                   <p class="text-[8px] sm:text-[9px] text-slate-400 font-bold uppercase">Status</p>
                   <p class="text-[10px] sm:text-xs font-bold text-slate-700">Planned</p>
                </div>
              </div>

              ${poi.note ? `<p class="text-slate-600 text-[10px] sm:text-[11px] leading-snug italic border-l-2 border-slate-200 pl-2 mb-1 sm:mb-2">"${poi.note}"</p>` : ''}
              <p class="text-slate-400 text-[9px] sm:text-[10px] mt-1.5 sm:mt-2 border-t pt-1.5 sm:pt-2">Schedule: ${day.date}</p>
            </div>
          </div>
        `;

        marker.bindPopup(popupContent, {
          className: 'custom-leaflet-popup',
          offset: [0, -5],
          maxWidth: 300
        });

        marker.on('click', (e: any) => {
          (window as any).L.DomEvent.stopPropagation(e);
          if (selectedDay !== day.dayNum) {
            isMapInteraction.current = true; // Mark as map interaction
            onSelectDay(day.dayNum);
          }
        });
        layersRef.current[`poi_${day.dayNum}_${poi.name}`] = marker;
      });
    });
  }, [days, selectedDay, onSelectDay]);

  useEffect(() => {
    if (!mapContainerRef.current || mapInstanceRef.current) return;

    const map = (window as any).L.map(mapContainerRef.current, {
      zoomControl: false,
      attributionControl: true
    }).setView([64.9, -18.5], 6.5);

    mapInstanceRef.current = map;

    (window as any).L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}', {
      maxZoom: 19,
      attribution: 'Tiles &copy; Esri'
    }).addTo(map);

    (window as any).L.control.zoom({
      position: 'bottomright'
    }).addTo(map);

    // Event listener to attach audio logic to dynamically rendered popup buttons
    map.on('popupopen', (e: any) => {
      const popupNode = e.popup._contentNode;
      const btn = popupNode.querySelector('.pronounce-btn');
      const container = popupNode.querySelector('[data-poi-name]');
      if (btn && container) {
        const name = container.getAttribute('data-poi-name');
        btn.addEventListener('click', (ev: any) => {
          ev.stopPropagation();
          handlePronounce(name, btn);
        });
      }
    });

    drawItinerary(map);

    return () => {
      if (mapInstanceRef.current) {
        mapInstanceRef.current.remove();
        mapInstanceRef.current = null;
      }
      if (audioContextRef.current) {
        audioContextRef.current.close();
      }
    };
  }, []);

  useEffect(() => {
    const map = mapInstanceRef.current;
    if (map) {
      drawItinerary(map);

      if (selectedDay !== lastSelectedDayRef.current) {
        if (!isMapInteraction.current) {
          const day = days.find(d => d.dayNum === selectedDay);
          if (day && day.routeCoords?.[0]) {
            const start = day.routeCoords[0];
            if (!isNaN(start.lat) && !isNaN(start.lng)) {
              map.invalidateSize();
              map.flyTo([start.lat, start.lng], isMobile() ? 9 : 10, {
                duration: 1.5,
                easeLinearity: 0.25
              });
            }
          }
        }
        isMapInteraction.current = false;
        lastSelectedDayRef.current = selectedDay;
      }
    }
  }, [selectedDay, drawItinerary, days]);

  return (
    <div className="relative h-full w-full">
      <style>{`
        .custom-leaflet-popup .leaflet-popup-content-wrapper {
          background: white;
          border-radius: 12px;
          padding: 0;
          overflow: hidden;
          box-shadow: 0 10px 25px -5px rgba(0, 0, 0, 0.4);
        }
        .custom-leaflet-popup .leaflet-popup-content {
          margin: 0;
        }
        .direction-arrow {
          pointer-events: none;
        }
        .leaflet-popup-tip {
          background: white;
        }
        @keyframes pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.5; }
        }
        .animate-pulse {
          animation: pulse 2s cubic-bezier(0.4, 0, 0.6, 1) infinite;
        }
      `}</style>
      <div ref={mapContainerRef} className="h-full w-full rounded-2xl overflow-hidden shadow-2xl border-2 border-slate-800 bg-slate-950" />
    </div>
  );
};

export default Map;

