              </div>

              ${poi.note ? `<p class="text-slate-600 text-[10px] sm:text-[11px] leading-snug italic border-l-2 border-slate-200 pl-2 mb-1 sm:mb-2">"${poi.note}"</p>` : ''}
              <p class="text-slate-400 text-[9px] sm:text-[10px] mt-1.5 sm:mt-2 border-t pt-1.5 sm:pt-2">Schedule: ${day.date}</p>
            </div>
          </div>
        `;

        marker.bindPopup(popupContent, {
          className: 'custom-leaflet-popup',
          offset: [0, -5],
          maxWidth: 300
        });

        marker.on('click', (e: any) => {
          (window as any).L.DomEvent.stopPropagation(e);
          if (selectedDay !== day.dayNum) {
            isMapInteraction.current = true; // Mark as map interaction
            onSelectDay(day.dayNum);
          }
        });
        layersRef.current[`poi_${day.dayNum}_${poi.name}`] = marker;
      });
    });
  }, [days, selectedDay, onSelectDay]);

  useEffect(() => {
    if (!mapContainerRef.current || mapInstanceRef.current) return;

    const map = (window as any).L.map(mapContainerRef.current, {
      zoomControl: false,
      attributionControl: true
    }).setView([64.9, -18.5], 6.5);

    mapInstanceRef.current = map;

    (window as any).L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}', {
      maxZoom: 19,
      attribution: 'Tiles &copy; Esri'
    }).addTo(map);

    (window as any).L.control.zoom({
      position: 'bottomright'
    }).addTo(map);

    // Event listener to attach audio logic to dynamically rendered popup buttons
    map.on('popupopen', (e: any) => {
      const popupNode = e.popup._contentNode;
      const btn = popupNode.querySelector('.pronounce-btn');
      const container = popupNode.querySelector('[data-poi-name]');
      if (btn && container) {
        const name = container.getAttribute('data-poi-name');
        btn.addEventListener('click', (ev: any) => {
          ev.stopPropagation();
          handlePronounce(name, btn);
        });
      }
    });

    drawItinerary(map);

    return () => {
      if (mapInstanceRef.current) {
        mapInstanceRef.current.remove();
        mapInstanceRef.current = null;
      }
      if (audioContextRef.current) {
        audioContextRef.current.close();
      }
    };
  }, []);

  useEffect(() => {
    const map = mapInstanceRef.current;
    if (map) {
      drawItinerary(map);

      if (selectedDay !== lastSelectedDayRef.current) {
        if (!isMapInteraction.current) {
          const day = days.find(d => d.dayNum === selectedDay);
          if (day && day.routeCoords?.[0]) {
            const start = day.routeCoords[0];
            if (!isNaN(start.lat) && !isNaN(start.lng)) {
              map.invalidateSize();
              map.flyTo([start.lat, start.lng], isMobile() ? 9 : 10, {
                duration: 1.5,
                easeLinearity: 0.25
              });
            }
          }
        }
        isMapInteraction.current = false;
        lastSelectedDayRef.current = selectedDay;
      }
    }
  }, [selectedDay, drawItinerary, days]);

  return (
    <div className="relative h-full w-full">
      <style>{`
        .custom-leaflet-popup .leaflet-popup-content-wrapper {
          background: white;
          border-radius: 12px;
          padding: 0;
          overflow: hidden;
          box-shadow: 0 10px 25px -5px rgba(0, 0, 0, 0.4);
        }
        .custom-leaflet-popup .leaflet-popup-content {
          margin: 0;
        }
        .direction-arrow {
          pointer-events: none;
        }
        .leaflet-popup-tip {
          background: white;
        }
        @keyframes pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.5; }
        }
        .animate-pulse {
          animation: pulse 2s cubic-bezier(0.4, 0, 0.6, 1) infinite;
        }
      `}</style>
      <div ref={mapContainerRef} className="h-full w-full rounded-2xl overflow-hidden shadow-2xl border-2 border-slate-800 bg-slate-950" />
    </div>
  );
};

export default Map;

import { GoogleGenAI, Modality } from "@google/genai";
import { ICELAND_ITINERARY } from "../constants";

const SYSTEM_INSTRUCTION = `
You are an expert Iceland Expedition Guide specializing in off-road 4x4 overlanding and F-Road navigation.
The user is planning a trip in August/September 2026. 
You have access to their planned itinerary:
${JSON.stringify(ICELAND_ITINERARY, null, 2)}

Key expertise areas:
1. F-Road conditions: Explain the difficulty of F26, F88, F208, and F249.
2. River crossings: Advise on how to gauge depth and the risk of rain.
3. Overlanding gear: Recommendations for modified 4x4s, fuel cans, and emergency beacons.
4. Weather: August variability, wind warnings, and sandstorms.
5. Scenic hidden gems near their planned route.

Always be encouraging but prioritize safety. If they ask about river crossings, emphasize that high-water events can happen even in August.
Keep responses concise and adventurous. Use Markdown for formatting.
`;

export async function getGeminiAdvice(messages: { role: 'user' | 'model', text: string }[]) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: messages.map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      })),
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
      }
    });

    return response.text || "I'm sorry, I couldn't process that. Try again!";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "The adventure guide is currently out of range (API Error). Check your connection and try again.";
  }
}

/**
 * Generates audio pronunciation for an Icelandic location name
 */
export async function getPronunciationAudio(text: string): Promise<string | undefined> {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.error("Gemini API Key is missing");
    return undefined;
  }

  // Always create a fresh instance to ensure the latest API key is used
  const ai = new GoogleGenAI({ apiKey });

  try {
    // Simplified prompt format as recommended for TTS models to avoid safety filters
    // and ensure the model focuses purely on audio synthesis.
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Say: ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });

    if (!response.candidates || response.candidates.length === 0) {
      console.warn("TTS Response has no candidates. This can happen due to safety filters or regional restrictions.");
      return undefined;
    }

    const candidate = response.candidates[0];

    // Check finish reason to see if safety filters were triggered (e.g., 'SAFETY' or 'RECITATION')
    if (candidate.finishReason && candidate.finishReason !== 'STOP') {
      console.warn(`TTS generation finished with reason: ${candidate.finishReason} for input: ${text}`);
    }

    const parts = candidate.content?.parts;
    if (!parts || parts.length === 0) {
      console.warn("No parts in candidate for TTS response.");
      return undefined;
    }

    // Iterate through all parts. While Modality.AUDIO is requested, 
    // the model may occasionally include a text part first.
    for (const part of parts) {
      if (part.inlineData?.data) {
        return part.inlineData.data;
      }
      if (part.text) {
        console.debug("TTS partial text response:", part.text);
      }
    }

    return undefined;
  } catch (error) {
    console.error("TTS Generation Error:", error);
    return undefined;
  }
}

// Helper functions for raw PCM audio decoding as required by Gemini API
export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

/**
 * Decodes raw PCM bytes into an AudioBuffer for playback
 */
export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1,
): Promise<AudioBuffer> {
  // Ensure the underlying buffer is correctly handled by creating a slice from the offset
  const arrayBuffer = data.buffer.slice(data.byteOffset, data.byteOffset + data.byteLength);
  const dataInt16 = new Int16Array(arrayBuffer);

  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      // Normalize raw 16-bit PCM [-32768, 32767] to float [-1.0, 1.0]
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}
